# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

import os
import secrets
from datetime import datetime, timedelta

from flask import Flask, request, jsonify, url_for
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = os.getenv("DATABASE_URL", "sqlite:///app.db")
app.config["SQLALCHEMY_TRACK_MODIFICATIONS"] = False
app.config["SECRET_KEY"] = os.getenv("SECRET_KEY", "dev-secret")
db = SQLAlchemy(app)


class PasswordResetToken(db.Model):
    __tablename__ = "password_reset_tokens"

    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(320), nullable=False, index=True)
    token = db.Column(db.String(128), nullable=False, unique=True, index=True)
    created_at = db.Column(db.DateTime, nullable=False, default=datetime.utcnow, index=True)
    expires_at = db.Column(db.DateTime, nullable=False, index=True)
    used_at = db.Column(db.DateTime, nullable=True, index=True)

    @property
    def is_expired(self):
        return datetime.utcnow() >= self.expires_at

    @property
    def is_used(self):
        return self.used_at is not None


def send_reset_email(to_email: str, reset_link: str) -> None:
    print(f"[MVP] Password reset email to {to_email}: {reset_link}")


def normalize_email(email: str) -> str:
    return (email or "").strip().lower()


@app.post("/api/auth/password-reset")
def request_password_reset():
    data = request.get_json(silent=True) or {}
    email = normalize_email(data.get("email"))
    if not email:
        return jsonify({"ok": True}), 200

    token = secrets.token_urlsafe(32)
    expires_in_minutes = int(os.getenv("PASSWORD_RESET_TOKEN_TTL_MINUTES", "30"))
    expires_at = datetime.utcnow() + timedelta(minutes=expires_in_minutes)

    prt = PasswordResetToken(email=email, token=token, expires_at=expires_at)
    db.session.add(prt)
    db.session.commit()

    reset_url = url_for("reset_password_form", token=token, _external=True)
    send_reset_email(email, reset_url)

    return jsonify({"ok": True}), 200


@app.get("/reset-password/<token>")
def reset_password_form(token):
    return jsonify({"token": token})


if __name__ == "__main__":
    with app.app_context():
        db.create_all()
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")), debug=os.getenv("FLASK_DEBUG", "0") == "1")